
"use client";

import { useFormState, useFormStatus } from 'react-dom';
import { signInWithEmailPassword } from '@/app/auth/actions';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useEffect } from 'react';
import { useToast } from '@/hooks/use-toast';
import { useRouter } from 'next/navigation';
import { Loader2 } from 'lucide-react';

const initialState = {
  message: '',
  success: false,
  redirectUrl: '',
};

function SubmitButton() {
  const { pending } = useFormStatus();
  return (
    <Button type="submit" className="w-full font-body" disabled={pending}>
      {pending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
      Sign In
    </Button>
  );
}

export function LoginForm() {
  const [state, formAction] = useFormState(signInWithEmailPassword, initialState);
  const { toast } = useToast();
  const router = useRouter();

  useEffect(() => {
    if (state?.message) {
      toast({
        title: state.success ? 'Success' : 'Error',
        description: state.message,
        variant: state.success ? 'default' : 'destructive',
      });
      if (state.success && state.redirectUrl) {
        router.push(state.redirectUrl);
      }
    }
  }, [state, toast, router]);

  return (
    <form action={formAction} className="space-y-4">
      <div>
        <Label htmlFor="email" className="font-body">Email</Label>
        <Input type="email" id="email" name="email" placeholder="m@example.com" required className="mt-1 font-body" />
      </div>
      <div>
        <Label htmlFor="password" className="font-body">Password</Label>
        <Input type="password" id="password" name="password" required className="mt-1 font-body" />
      </div>
      <SubmitButton />
    </form>
  );
}
